"use client";

import React, { useState, useEffect } from 'react';
import { 
  TrendingUp, 
  ArrowLeft, 
  Calendar, 
  Wallet, 
  PieChart, 
  Percent, 
  Loader2,
  AlertCircle
} from 'lucide-react';

/* ======== TYPY ======== */

interface TimelineItem {
  month: number;
  totalValue: number;
  accumulatedProfit: number;
}

interface ObliczeniaWynik {
  daily: number;
  weekly: number;
  monthly: number;
  yearly: number;
  total: number;
  duration: string; 
  timeline: TimelineItem[];
}

interface Obligacja {
  symbol: string;
  oprocentowaniePierwszyRok: number;
  okresLata: number;
  kapitalizacja: boolean;
}

/* ======== KOMPONENTY ======== */

function WynikGlownyKafelek({
  wyniki,
  formatPLN,
}: {
  wyniki: ObliczeniaWynik;
  formatPLN: (value: number | undefined) => string;
}) {
  return (
    <div className="w-full">
      <div
        style={{
          background: 'linear-gradient(135deg, #0071E3 0%, #00C7BE 100%)',
        }}
        className="p-6 md:p-8 rounded-3xl text-white shadow-xl flex justify-between items-center"
      >
        <div>
          <p className="opacity-90 mb-1">Zysk całkowity (netto)</p>
          <h3 className="text-4xl font-bold">{formatPLN(wyniki.total)}</h3>
        </div>
        <div className="bg-white/20 px-4 py-2 rounded-xl text-sm">
          Okres: {wyniki.duration}
        </div>
      </div>
    </div>
  );
}

/* ======== STRONA ======== */

export default function KalkulatorPage() {
  const [kwota, setKwota] = useState<number | ''>(1000);
  const [wybranySymbol, setWybranySymbol] = useState<string>('');
  const [listaObligacji, setListaObligacji] = useState<Obligacja[]>([]);
  const [wyniki, setWyniki] = useState<ObliczeniaWynik | null>(null);

  const [loading, setLoading] = useState(false);
  const [loadingObligacje, setLoadingObligacje] = useState(true);
  const [error, setError] = useState<string | null>(null);

  /* 🔴 KLUCZOWE */
  const BACKEND_URL = process.env.NEXT_PUBLIC_BACKEND_URL;

  /* ======== FETCH OBLIGACJI ======== */
  useEffect(() => {
    if (!BACKEND_URL) {
      setError('Brak NEXT_PUBLIC_BACKEND_URL w .env.local');
      setLoadingObligacje(false);
      return;
    }

    const fetchObligacje = async () => {
      try {
        const res = await fetch(`${BACKEND_URL}/obligacje`);
        if (!res.ok) throw new Error('Błąd pobierania obligacji');
        const data: Obligacja[] = await res.json();
        setListaObligacji(data);
        if (data.length > 0) setWybranySymbol(data[0].symbol);
      } catch (err) {
        setError('Nie udało się pobrać listy obligacji.');
      } finally {
        setLoadingObligacje(false);
      }
    };

    fetchObligacje();
  }, [BACKEND_URL]);

  /* ======== OBLICZENIA ======== */
  const handleOblicz = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    setWyniki(null);

    if (!kwota || kwota <= 0) {
      setError('Podaj poprawną kwotę.');
      return;
    }

    if (!wybranySymbol) {
      setError('Wybierz obligację.');
      return;
    }

    if (!BACKEND_URL) {
      setError('Brak BACKEND_URL.');
      return;
    }

    setLoading(true);

    try {
      const res = await fetch(
        `${BACKEND_URL}/calc?kwota=${kwota}&symbol=${wybranySymbol}`
      );

      if (!res.ok) {
        throw new Error(`Błąd serwera: ${res.status}`);
      }

      const data: ObliczeniaWynik = await res.json();
      setWyniki(data);
    } catch (err: any) {
      setError(err.message || 'Błąd połączenia z backendem.');
    } finally {
      setLoading(false);
    }
  };

  const formatPLN = (value?: number) =>
    value === undefined
      ? '-'
      : new Intl.NumberFormat('pl-PL', {
          style: 'currency',
          currency: 'PLN',
        }).format(value);

  /* ======== RENDER ======== */

  return (
    <div style={{ padding: 40 }}>
      <h1>Kalkulator obligacji</h1>

      {loadingObligacje ? (
        <Loader2 className="animate-spin" />
      ) : (
        <form onSubmit={handleOblicz}>
          <input
            type="number"
            value={kwota}
            onChange={(e) => setKwota(Number(e.target.value))}
          />

          <select
            value={wybranySymbol}
            onChange={(e) => setWybranySymbol(e.target.value)}
          >
            {listaObligacji.map((o) => (
              <option key={o.symbol} value={o.symbol}>
                {o.symbol}
              </option>
            ))}
          </select>

          <button disabled={loading}>
            {loading ? 'Liczenie…' : 'Oblicz'}
          </button>
        </form>
      )}

      {error && <p style={{ color: 'red' }}>{error}</p>}

      {wyniki && (
        <>
          <WynikGlownyKafelek
            wyniki={wyniki}
            formatPLN={formatPLN}
          />
        </>
      )}
    </div>
  );
}